args.sparql:
SELECT ?journalistLabel WHERE { 
 wd:Q151907 wdt:P1449 ?nickname .
 ?nickname wdt:P1906 wd:Q17612377 .
 wd:Q17612377 rdfs:label ?journalistLabel .
 FILTER(LANG(?journalistLabel) = 'en')
}

SELECT ?journalistLabel WHERE { 
 wd:Q151907 wdt:P3938 ?journalist .
 ?journalist rdfs:label ?journalistLabel .
 FILTER(LANG(?journalistLabel) = 'en')
}
